class Solution {
    public boolean[] canMakePalindromeQueries(String s, int[][] queries) {
        boolean[] answer = new boolean[queries.length];
        for (int i = 0; i < queries.length; i++) {
            int[] query = queries[i];
            int a = query[0], b = query[1], c = query[2], d = query[3];
            String left = s.substring(a, b + 1);
            String right = s.substring(c, d + 1);
            int[] leftCount = new int[26];
            int[] rightCount = new int[26];
            for (char ch : left.toCharArray()) {
                leftCount[ch - 'a']++;
            }
            for (char ch : right.toCharArray()) {
                rightCount[ch - 'a']++;
            }
            int midLeft = s.substring(b + 1, s.length() / 2);
            int midRight = s.substring(s.length() / 2, c);
            int[] midCount = new int[26];
            for (char ch : midLeft.toCharArray()) {
                midCount[ch - 'a']++;
            }
            for (char ch : midRight.toCharArray()) {
                midCount[ch - 'a']++;
            }
            int oddCount = 0;
            for (int j = 0; j < 26; j++) {
                oddCount += (midCount[j] % 2);
            }
            answer[i] = oddCount <= 1;
        }
        return answer;
    }
}
